let otpBuiseness = $(".otp_buiseness");
let otpBoxOne = $("#otpBuiseness1");
let otpBoxTwo = $("#otpBuiseness2");
let otpBoxThree = $("#otpBuiseness3");
let otpBoxFour = $("#otpBuiseness4");
let businessId = $("#hidden_value");

  $(".al_manage").click(function() {
    $(".al_wrapper").show();
});



  otpBuiseness.on("input", function (e) {
    let o = $(".otp_buiseness").index(this);
    1 === e.target.value.length
      ? o < $(".otp_buiseness").length - 1 &&
        $(".otp_buiseness")
          .eq(o + 1)
          .focus()
      : 0 === e.target.value.length &&
        o > 0 &&
        $(".otp_buiseness")
          .eq(o - 1)
          .focus();
  });
    otpBuiseness.on("keydown", function (e) {
      let o = $(".otp_buiseness").index(this);
      "Backspace" === e.key &&
        0 === e.target.value.length &&
        o > 0 &&
        $(".otp_buiseness")
          .eq(o - 1)
          .focus();
    });
    otpBuiseness.on("keypress", function (e) {
      $(this).val().length >= 1 && e.preventDefault();
    });
    $("#optBox1, #otpBox2, #otpBox3, #otpBox4").on("input", function () {
      var e = !0;
      $("#optBox1, #otpBox2, #otpBox3, #otpBox4").each(function () {
        if ("" === $(this).val()) return (e = !1), !1;
      }),
        e
          ? ($("#btn-signup5").prop("disabled", !1),
            $("#btn-signup5").removeClass("disable_btn"),
            $("#btn-signup5").addClass("signup_verify_btn"))
          : ($("#btn-signup5").prop("disabled", !0),
            $("#btn-signup5").addClass("disable_btn"),
            $("#btn-signup5").removeClass("signup_verify_btn"));
    })

    function formatName(e) {
        return e
          .split(" ")
          .map(function (e) {
            return e.charAt(0).toUpperCase() + e.slice(1).toLowerCase();
          })
          .join(" ");
      }

      otpBoxFour.on('input', function() {
        if (otpBoxOne.val() && otpBoxTwo.val() && otpBoxThree.val() && otpBoxFour.val()) {
            let e = formatName($("#name").val()),
                o = $("#phone").val(),
                n = $("#email").val().toLowerCase(),
                t = 2,
                s = otpBoxOne.val() + otpBoxTwo.val() + otpBoxThree.val() + otpBoxFour.val(),
                j = businessId.val();
    
            // Proceed with AJAX request
            $.ajax({
                type: "POST",
                url: "https://www.bookmyplayer.com/register/validate",
                data: {
                    _token: $('meta[name="csrf-token"]').attr("content"),
                    name: e,
                    phone: o,
                    email: n,
                    type_id: t,
                    otp: s,
                    bus_id:j
                },
                success(e) {
                    if (e.status == 1) {
                        if (null != e.redirect_url && e.redirect_url != "") {
                            window.location.href = e.redirect_url;
                        } else {
                            location.reload();
                        }
                    } else if (e.status == 0) {
                        $('#errorMsgOtp').text(e.message);
                        $('#errorMsgOtp').removeClass("d-none");
                    }
                },
                error(e) {
                  $('#errorMsgOtp').text(JSON.stringify(e));
                  $('#errorMsgOtp').removeClass("d-none");
                },
            });
        }
    });
    